#include <stdio.h>
#include <stdlib.h>
#include <limits.h>

// Structure to represent a min-heap node
typedef struct Node {
    int val;
    struct Node* left;
    struct Node* right;
} Node;

// Function to create a new min-heap node
Node* createNode(int val) {
    Node* newNode = (Node*)malloc(sizeof(Node));
    newNode->val = val;
    newNode->left = newNode->right = NULL;
    return newNode;
}

// Function to insert a new node into the min-heap
void insertNode(Node** root, int val) {
    Node* newNode = createNode(val);
    if (*root == NULL) {
        *root = newNode;
    } else {
        Node* current = *root;
        Node* parent = NULL;
        while (current != NULL) {
            parent = current;
            if (newNode->val < current->val) {
                current = current->left;
            } else {
                current = current->right;
            }
        }
        if (newNode->val < parent->val) {
            parent->left = newNode;
        } else {
            parent->right = newNode;
        }
    }
}

// Function to remove the smallest node from the min-heap
int removeSmallest(Node** root) {
    if (*root == NULL) return INT_MAX;
    int smallest = (*root)->val;
    Node* temp = *root;
    *root = (*root)->right;
    free(temp);
    return smallest;
}

// Function to find the k-th largest value
int findKthLargest(Node* root, int k) {
    if (root == NULL) return INT_MAX;
    int count = 0;
    Node* current = root;
    while (current != NULL) {
        count++;
        if (count == k) return current->val;
        current = current->right;
    }
    return INT_MAX;
}

