    constructor(k, nums) {
        this.k = k;
        this.pq = [];
        for (let num of nums) {
            this.add(num);
        }
    }

    add(val) {
        this.pq.push(val);
        this.pq.sort((a, b) => a - b);
        if (this.pq.length > this.k) this.pq.pop();
